+}
+
+impl ComputeOps for WorkerPoolCompute {
+    fn matmul(&self, a: &Tensor, b: &Tensor) -> Tensor {
+        // For single matmul, use SIMD (workers have overhead)
+        self.fallback.matmul(a, b)
