+    /// CPU fallback for small matrices
+    fn cpu_matmul(&self, a: &Tensor, b: &Tensor) -> Tensor {
+        let m = a.shape().rows();
+        let k = a.shape().cols();
+        let n = b.shape().cols();
+
+        let a_data = a.data();
+        let b_data = b.data();
+        let mut result = vec![0.0f32; m * n];
+
+        for i in 0..m {
+            for j in 0..n {
+                let mut sum = 0.0;
+                for kk in 0..k {
+                    sum += a_data[i * k + kk] * b_data[kk * n + j];
+                }
+                result[i * n + j] = sum;
+            }
+        }
+
+        Tensor::from_vec(result, TensorShape::matrix(m, n))
+    }
+}
