+
+/// Compile a shader
+fn compile_shader(gl: &WebGl2RenderingContext, shader_type: u32, source: &str) -> Result<WebGlShader, JsValue> {
+    let shader = gl.create_shader(shader_type)
+        .ok_or_else(|| JsValue::from_str("Failed to create shader"))?;
