+    float sum = 0.0;
+    for (float k = 0.0; k < K; k += 1.0) {
+        float a = texture(u_A, vec2((k + 0.5) / K, (i + 0.5) / M)).r;
+        float b = texture(u_B, vec2((j + 0.5) / N, (k + 0.5) / K)).r;
