+mod tests {
+    use super::*;
+
+    #[test]
+    fn test_amm_creation() {
+        let amm = ComputeAMM::new(1_000_000, 1_000_000).unwrap();
+        assert_eq!(amm.get_reserve_ruv(), 1_000_000);
+        assert_eq!(amm.get_reserve_compute(), 1_000_000);
